record.field:
for rec in records:
    values = {}
    if rec.x_function_id:
        values['x_name'] = rec.x_function_id.with_context(lang='ar_001').display_name or rec.x_function_id.display_name
    if rec.x_functional_area_id:
        values['x_print_functional_area_name'] = rec.x_functional_area_id.with_context(lang='ar_001').display_name or rec.x_functional_area_id.display_name
    if values:
        rec.sudo().write(values)

for rec in records:
    values = {}
    if rec.x_function_id:
        values['x_name'] = rec.x_function_id.with_context(lang='ar_001').display_name or rec.x_function_id.display_name
    if rec.x_functional_area_id:
        values['x_print_functional_area_name'] = rec.x_functional_area_id.with_context(lang='ar_001').display_name or rec.x_functional_area_id.display_name
    if values:
        rec.sudo().write(values)

for rec in records:
    values = {}
    if rec.x_function_id and not rec.x_name:
        values['x_name'] = rec.x_function_id.with_context(lang='ar_001').display_name or rec.x_function_id.display_name
    if rec.x_functional_area_id and not rec.x_print_functional_area_name:
        values['x_print_functional_area_name'] = rec.x_functional_area_id.with_context(lang='ar_001').display_name or rec.x_functional_area_id.display_name
    if values:
        rec.sudo().write(values)

for rec in records:
    if rec.x_tor_state and rec.x_tor_state != 'draft':
        continue

    values = {}
    if rec.partner_name and not rec.x_tor_recipient_name:
        values['x_tor_recipient_name'] = rec.partner_name

    if rec.job_id:
        translated_job_title = rec.job_id.with_context(lang='ar_001').name or rec.job_id.name
        translated_department_name = rec.job_id.department_id.with_context(lang='ar_001').display_name if rec.job_id.department_id else False
        if translated_job_title and rec.x_tor_job_title != translated_job_title:
            values['x_tor_job_title'] = translated_job_title
        if rec.job_id.department_id and rec.x_tor_department_id != rec.job_id.department_id:
            values['x_tor_department_id'] = rec.job_id.department_id.id
        if translated_department_name and rec.x_tor_department_name != translated_department_name:
            values['x_tor_department_name'] = translated_department_name

    if values:
        rec.sudo().write(values)

for rec in records:
    if not rec.x_tor_signed_attachment_id:
        continue

    rec.sudo().write({
        'x_tor_state': 'signed',
        'x_tor_signed_on': datetime.datetime.now(),
    })
    rec.message_post(body='Signed TOR PDF linked to the applicant record.')
